        /// Р В Р’В Р РҶР вҖҡРІвҖһСһР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ°Р В Р РӢР В РЎвҖңР В Р РӢР В Р РҸ Р В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸ Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВ Р В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р РӢР В Р вҖ°, Р В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’Вө Kokonoe Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’Вө Р В Р РӢР В РЎвҖңР В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡРІРӮСң.
        /// </summary>
        public async Task<string?> SendSystemQueryAsync(string prompt, bool useTools = false, CancellationToken ct = default, string? agentId = null)
        {
            var diagWatch = Stopwatch.StartNew();
            var target = ResolveAgentTarget(agentId);
            var diagProvider = string.IsNullOrWhiteSpace(agentId) ? ActiveProviderLabel() : $"{target.Provider}:{agentId}";
            var diagModel = target.Model;
            const string diagChannel = "system_agent";
            RecordLlmRequest(diagProvider, diagModel, diagChannel);

            var history = new List<HistoryEntry>();
            var dateStamp = $"\n\n=== Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮв„ўР В Р’В Р РҺРЎвҖәР В Р’В Р РҺРІРӮв„ў/Р В Р’В Р вҖҷР’В§Р В Р’В Р РҺРІРӮв„ўР В Р’В Р В Р вҖ№ ===\nР В Р’В Р В Р вҖ№Р В Р РӢР В Р вҖ°Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ: {DateTime.Now:dddd, dd MMMM yyyy}, {DateTime.Now:HH:mm}";
            var systemContent = SYSTEM_PROMPT + BuildCapabilityPrompt(agentId) + dateStamp;

            history.Add(new HistoryEntry("user", prompt));

            try
            {
                for (int round = 0; round < (useTools ? 5 : 1); round++)
                {
                    var messages = new List<object> { new { role = "system", content = SanitizeContent(systemContent) } };
                    foreach (var h in history)
                    {
                        if (h.Role == "assistant_tool_calls")
                        {
                            var obj = JObject.Parse(h.Content.ToString()!);
                            messages.Add(new { role = "assistant", content = obj["content"]?.ToString(), tool_calls = obj["tool_calls"] });
                        }
                        else if (h.Role == "tool")
                            messages.Add(new { role = "tool", tool_call_id = h.ToolCallId, name = h.Name, content = h.Content });
                        else
                            messages.Add(new { role = h.Role, content = h.Content });
                    }

                    var sysProvider = target.Provider;
                    var sysIsOllamaCloud = sysProvider.Equals("ollama-cloud", StringComparison.OrdinalIgnoreCase);
                    var sysIsClaude = sysProvider.Equals("claude", StringComparison.OrdinalIgnoreCase);
                    var sysModel = target.Model;
                    var sysUrl = target.Url;
                    
                    object reqBody;
                    if (sysIsClaude)
                    {
                        reqBody = new
                        {
                            model = sysModel,
                            max_tokens = SystemMaxTokens,
                            temperature = target.Temperature,
                            system = SanitizeContent(systemContent),
                            messages = history.Where(h => h.Role != "tool" && h.Role != "assistant_tool_calls")
                                .Select(h => new { role = h.Role, content = h.Content })
                                .ToArray()
                        };
                    }
                    else if (useTools && Obsidian != null && round < 4)
                        reqBody = new { model = sysModel, messages, tools = TOOLS, tool_choice = "auto", max_tokens = SystemMaxTokens, temperature = target.Temperature, stream = false };
                    else
                        reqBody = new { model = sysModel, messages, max_tokens = SystemMaxTokens, temperature = target.Temperature, stream = false };

                    var json = JsonConvert.SerializeObject(reqBody);
                    HttpResponseMessage? resp = null;
                    string? usedOllamaKey = null;
                    int attempts = sysIsOllamaCloud ? GetOllamaAttemptCount(agentId) : 1;

                    for (int attempt = 0; attempt < attempts; attempt++)
                    {
                        var httpContent = new StringContent(json, Encoding.UTF8, "application/json");
                        using var req = new HttpRequestMessage(HttpMethod.Post, sysUrl) { Content = httpContent };
                        if (sysIsClaude)
                        {
                            req.Headers.Add("x-api-key", _claudeApiKey);
                            req.Headers.Add("anthropic-version", "2023-06-01");
                        }
                        else if (sysIsOllamaCloud)
                        {
                            usedOllamaKey = ResolveOllamaKey(agentId);
                            if (!string.IsNullOrEmpty(usedOllamaKey))
                                req.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", usedOllamaKey);
                        }

                        resp = await _http.SendAsync(req, ct);
                        if (resp.IsSuccessStatusCode)
                        {
                            if (sysIsOllamaCloud && !string.IsNullOrEmpty(usedOllamaKey))
                                RecordOllamaKeyRequest(agentId, usedOllamaKey);
                            break;
                        }
                        if (sysIsOllamaCloud && (int)resp.StatusCode == 429 && !string.IsNullOrEmpty(usedOllamaKey))
                        {
                            MarkOllamaKeyRateLimited(agentId, usedOllamaKey);
                            resp.Dispose();
                            resp = null;
                            continue;
                        }
                        else break;
                    }

                    if (resp == null || !resp.IsSuccessStatusCode)
                    {
                        RecordLlmFailure(diagProvider, diagModel, diagChannel, (int?)resp?.StatusCode, "API Error", diagWatch, "system_agent_fail");
                        return null;
                    }

                    var respText = await resp.Content.ReadAsStringAsync(ct);
                    var respObj = JObject.Parse(respText);
                    if (sysIsClaude)
                    {
                        var claudeText = respObj["content"]?.FirstOrDefault()?["text"]?.ToString();
                        RecordLlmSuccess(diagProvider, diagModel, diagChannel, diagWatch);
                        return CleanGarbage(claudeText ?? "");
                    }

                    var message = respObj["choices"]?[0]?["message"] as JObject;
                    if (message == null) return null;

                    var toolCalls = message["tool_calls"] as JArray;
                    var rawContent = message["content"]?.ToString() ?? "";
                    var reasoning = message["reasoning_content"]?.ToString() ?? "";

                    if (!string.IsNullOrWhiteSpace(reasoning))
                        OnProgress?.Invoke("thought", reasoning);

                    if (toolCalls == null || toolCalls.Count == 0)
                    {
                        RecordLlmSuccess(diagProvider, diagModel, diagChannel, diagWatch);
                        return CleanGarbage(rawContent);
                    }

                    history.Add(new HistoryEntry("assistant_tool_calls", message.ToString()));
                    foreach (var call in toolCalls)
                    {
                        var callId = call["id"]?.ToString() ?? Guid.NewGuid().ToString();
                        var funcName = call["function"]?["name"]?.ToString() ?? "";
                        var argsRaw = call["function"]?["arguments"]?.ToString() ?? "{}";
                        OnProgress?.Invoke("tool", $"Р В Р’В Р РҺРІРӮв„ўР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В Р РҸ: {funcName}");
                        var result = await ExecuteToolAsync(funcName, JObject.Parse(argsRaw), ct).ConfigureAwait(false);
                        history.Add(new HistoryEntry("tool", result, ToolCallId: callId, Name: funcName));
                    }
                }
                return null;
            }
            catch (Exception ex)
            {
                RecordLlmFailure(diagProvider, diagModel, diagChannel, null, ex.Message, diagWatch, "system_agent_exception");
                return null;
            }
        }

        public async Task<string?> SendSystemVisionQueryAsync(
            string prompt,
            byte[] imageBytes,
            string imageMime = "image/jpeg",
            CancellationToken ct = default,
            string? agentId = null)
        {
            var diagWatch = Stopwatch.StartNew();
            var target = ResolveAgentTarget(agentId);
            var diagProvider = string.IsNullOrWhiteSpace(agentId) ? ActiveProviderLabel() : $"{target.Provider}:{agentId}";
            var diagModel = string.IsNullOrWhiteSpace(agentId) ? ActiveModelLabel(imageRequest: true) : target.Model;
            const string diagChannel = "system:image";
            RecordLlmRequest(diagProvider, diagModel, diagChannel);

            try
            {
                if (imageBytes == null || imageBytes.Length == 0)
                    return null;

                var sendImageBytes = imageBytes;
                var sendImageMime = imageMime;
                // System vision keeps the caller's compact format first; chat path handles PNG retry on failures.

                var dateStamp = $"\n\n=== Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮв„ўР В Р’В Р РҺРЎвҖәР В Р’В Р РҺРІРӮв„ў/Р В Р’В Р вҖҷР’В§Р В Р’В Р РҺРІРӮв„ўР В Р’В Р В Р вҖ№ ===\nР В Р’В Р В Р вҖ№Р В Р РӢР В Р вҖ°Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ: {DateTime.Now:dddd, dd MMMM yyyy}, {DateTime.Now:HH:mm}";
                var systemContent = SYSTEM_PROMPT + BuildCapabilityPrompt(agentId) + dateStamp;
                var b64 = Convert.ToBase64String(sendImageBytes);

                var visionIsClaude = target.Provider.Equals("claude", StringComparison.OrdinalIgnoreCase);
                var visionIsOllamaCloud = target.Provider.Equals("ollama-cloud", StringComparison.OrdinalIgnoreCase);

                object imageBlock = visionIsClaude
                    ? new { type = "image", source = new { type = "base64", media_type = sendImageMime, data = b64 } }
                    : new { type = "image_url", image_url = new { url = $"data:{sendImageMime};base64,{b64}" } };

                object userContent = new object[]
                {
                    new { type = "text", text = prompt },
                    imageBlock
                };

                var targetModel = target.Model;
                var targetUrl = target.Url;
                if (string.IsNullOrWhiteSpace(agentId) && !string.IsNullOrWhiteSpace(_visionModel))
                    targetModel = _visionModel;
                if (!visionIsClaude && string.IsNullOrWhiteSpace(agentId) && !string.IsNullOrWhiteSpace(_visionUrl))
                    targetUrl = _visionUrl;

                var visionModels = BuildVisionModelCascade(targetModel, visionIsOllamaCloud);
                HttpResponseMessage? resp = null;
                string? lastError = null;
                int? lastStatus = null;
                string lastModel = targetModel;

                foreach (var modelAttempt in visionModels)
                {
                    lastModel = modelAttempt;
                    object reqBody;
                    if (visionIsClaude)
                    {
                        reqBody = new
                        {
                            model = modelAttempt,
                            max_tokens = SystemMaxTokens,
                            temperature = target.Temperature,
                            system = SanitizeContent(systemContent),
                            messages = new[]
                            {
                                new { role = "user", content = userContent }
                            }
                        };
                    }
                    else
                    {
                        reqBody = new
                        {
                            model = modelAttempt,
                            messages = new object[]
                            {
                                new { role = "system", content = SanitizeContent(systemContent) },
                                new { role = "user", content = userContent }
                            },
                            max_tokens = SystemMaxTokens,
                            temperature = target.Temperature,
                            stream = false
                        };
                    }

                    var json = JsonConvert.SerializeObject(reqBody);
                    int attempts = visionIsOllamaCloud ? GetOllamaAttemptCount(agentId) : 1;
                    resp = null;
                    string? ollamaKey = null;

                    for (int attempt = 0; attempt < attempts; attempt++)
                    {
                        using var req = new HttpRequestMessage(HttpMethod.Post, targetUrl)
                        {
                            Content = new StringContent(json, Encoding.UTF8, "application/json")
                        };

                        if (visionIsClaude && !string.IsNullOrWhiteSpace(_claudeApiKey))
                        {
                            req.Headers.Add("x-api-key", _claudeApiKey);
                            req.Headers.Add("anthropic-version", "2023-06-01");
                        }
                        else if (visionIsOllamaCloud)
                        {
                            ollamaKey = ResolveOllamaKey(agentId);
                            if (!string.IsNullOrEmpty(ollamaKey))
                                req.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", ollamaKey);
                        }

                        resp = await _http.SendAsync(req, ct);
                        if (resp.IsSuccessStatusCode)
                        {
                            if (visionIsOllamaCloud && !string.IsNullOrEmpty(ollamaKey))
                                RecordOllamaKeyRequest(agentId, ollamaKey);
                            break;
                        }

                        if (visionIsOllamaCloud && (int)resp.StatusCode == 429
                            && !string.IsNullOrEmpty(ollamaKey))
                        {
                            MarkOllamaKeyRateLimited(agentId, ollamaKey);
                            resp.Dispose();
                            resp = null;
                            continue;
                        }

                        break;
                    }

                    if (resp != null && resp.IsSuccessStatusCode)
                        break;

                    lastStatus = resp == null ? null : (int)resp.StatusCode;
                    lastError = resp == null ? "no live key/response" : await resp.Content.ReadAsStringAsync(ct);
                    var shouldTryNextVision = visionIsOllamaCloud
                        && lastStatus is 400 or 500
                        && modelAttempt != visionModels.Last()
                        && LooksLikeVisionModelFailure(lastError);
                    resp?.Dispose();
                    resp = null;

                    if (shouldTryNextVision)
                    {
                        RecordLlmFailure(diagProvider, modelAttempt, diagChannel, lastStatus, lastError, diagWatch, "system_vision_fallback_retry");
                        continue;
                    }

                    break;
                }

                if (resp == null || !resp.IsSuccessStatusCode)
                {
                    var status = resp == null ? lastStatus : (int)resp.StatusCode;
                    var error = resp == null ? (lastError ?? "no live key/response") : await resp.Content.ReadAsStringAsync(ct);
                    RecordLlmFailure(diagProvider, lastModel, diagChannel, status, error, diagWatch, "system_vision");
                    return null;
                }

                var respText = await resp.Content.ReadAsStringAsync(ct);
                var respObj = JObject.Parse(respText);
                var reply = visionIsClaude
                    ? respObj["content"]?.FirstOrDefault()?["text"]?.ToString()
                    : respObj["choices"]?[0]?["message"]?["content"]?.ToString();

                RecordLlmSuccess(diagProvider, diagModel, diagChannel, diagWatch);
                return CleanGarbage(reply ?? "");
            }
            catch (Exception ex)
            {
                RecordLlmFailure(diagProvider, diagModel, diagChannel, null, ex.Message, diagWatch, "system_vision_exception");
                return null;
            }
        }

        public void RestoreHistory(IEnumerable<(string role, string content)> messages, int maxMessages = 25, string? memoryPrefix = null)
        {
            lock (_histLock)
            {
                _history.Clear();

                // Р В Р’В Р В РІРӮРҺР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһ Р В Р РӢР РҶР вҖҡРЎСҡ vault memory bootstrap Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ
                // Р В Р’В Р вҖҷР’ВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В·Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸР В Р РӢР РҶР вҖҡРЎСҡ Kokonoe Р В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСңР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ў Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ° Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РЎвҖңР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸ Р В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р РӢР В РІРӮСҷР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡ Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В»Р В Р РӢР РҶР вҖҡРІРӮСҡ
                if (!string.IsNullOrEmpty(memoryPrefix))
                    _history.Add(new HistoryEntry("system", memoryPrefix));

                // Р В Р’В Р РҶР вҖҡРІвҖһСһР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ MAX_HISTORY_ENTRIES Р В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸ Р В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰР В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҶР вҖҡРІРӮСҡ
                var effectiveMax = Math.Min(maxMessages, MAX_HISTORY_ENTRIES);
                foreach (var (role, content) in messages.TakeLast(effectiveMax))
                    _history.Add(new HistoryEntry(role, content));
            }
        }

