                lock (_histLock) { _history.Add(new HistoryEntry("user", userContent)); }

                // Р В Р’В Р РҺРЎСҹР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РЎвҖңР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸ Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р РӢР РҶР вҖҡР’В Р В Р’В Р вҖҷР’ВөР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖң Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° text-only Р В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’Вұ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р РҸР В Р’В Р РҺРІРӮвҖңР В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р РӢР В РІРӮСҷР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ Р В Р’В Р В РІРӮВ  Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡР В Р’В Р РҺРІРӮвҖқР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ
