                            ? visionModelOverride
                            : _visionModel;
                    // Р В Р’В Р В РІРӮРҺР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһ Р В Р РӢР РҶР вҖҡРЎСҡ VisionUrl Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ image requests Р В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р СһРІРӮВҳР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ° Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң endpoint (Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷ. Р В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң Ollama)
                    if (isImageRequest && string.IsNullOrWhiteSpace(agentId) && !string.IsNullOrWhiteSpace(_visionUrl))
                        targetUrl = _visionUrl;

                    object reqBody;
                    if (isClaude)
                    {
                        // Claude API format
                        var claudeMessages = BuildClaudeMessages(systemContent);
                        if (useTools && !forceNoTools)
                        {
                            var tools = BuildClaudeTools();
                            reqBody = new
                            {
                                model = targetModel,
                                max_tokens = MainMaxTokens,
                                temperature = agentTarget.Temperature,
                                system = SanitizeContent(systemContent),
                                messages = claudeMessages,
                                tools = tools,
                                tool_choice = (object)(looksLikeVaultOp && round == 0 ? new { type = "tool", name = DetectBestTool(userText!) } : "auto")
                            };
                        }
                        else
                        {
                            reqBody = new
                            {
                                model = targetModel,
                                max_tokens = MainMaxTokens,
                                temperature = agentTarget.Temperature,
                                system = SanitizeContent(systemContent),
                                messages = claudeMessages
                            };
                        }
                    }
                    else
                    {
                        // LM Studio / OpenAI-compatible format
                        if (useTools && !forceNoTools)
                        {
                            var toolChoice = looksLikeVaultOp && round == 0
                                ? (object)new { type = "function", function = new { name = DetectBestTool(userText!) } }
                                : "auto";
                            reqBody = new { model = targetModel, messages, tools = TOOLS, tool_choice = toolChoice, max_tokens = MainMaxTokens, temperature = agentTarget.Temperature, stream = false };
                        }
                        else
                            reqBody = new { model = targetModel, messages, max_tokens = MainMaxTokens, temperature = agentTarget.Temperature, stream = false };
                    }

                    var json = JsonConvert.SerializeObject(reqBody);

                    // Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸ Ollama Cloud Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ retry-loop Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһ Р В Р’В Р вҖҷР’В¶Р В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В»Р В Р РӢР В РІРӮв„–Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳ 429.
                    // Р В Р’В Р РҺРІРӮС”Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВҰ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р РӢР РҶР вҖҡР’В Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В» Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҺРІРӮСҡР В Р’В Р вҖҷР’В»Р В Р РӢР РҺРІРӮСҡ; Р В Р РӢР В Р РҸР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВ Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮВҳ Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р’В Р СһРІРӮВҳР В Р РӢР В РІРӮСҷР В Р РӢР РҺРІРӮСҡР В Р’В Р вҖҷР’В¶Р В Р’В Р В РІРӮВҰР В Р РӢР В Р РҸ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° Р В Р’В Р вҖҷР’В· cooldown.
                    int ollamaAttempts = isOllamaCloud ? GetOllamaAttemptCount(agentId) : 1;
                    HttpResponseMessage? resp = null;
                    string? usedOllamaKey = null;

                    for (int attempt = 0; attempt < ollamaAttempts; attempt++)
                    {
                        var httpContent = new StringContent(json, Encoding.UTF8, "application/json");
                        using var llmReq = new HttpRequestMessage(HttpMethod.Post, targetUrl) { Content = httpContent };

                        if (isClaude)
                        {
                            llmReq.Headers.Add("x-api-key", _claudeApiKey);
                            llmReq.Headers.Add("anthropic-version", "2023-06-01");
                        }
                        else if (isOllamaCloud)
                        {
                            usedOllamaKey = ResolveOllamaKey(agentId);
                            if (!string.IsNullOrEmpty(usedOllamaKey))
                                llmReq.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", usedOllamaKey);
                        }

                        resp = await _http.SendAsync(llmReq, ct);

                        // Р В Р’В Р В РІвҖҡВ¬Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡР’ВҰ Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ў Р В Р РӢР РҺРІРӮСҡ Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҺРІРӮСҡР В Р’В Р вҖҷР’В» Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ
                        if (resp.IsSuccessStatusCode)
                        {
                            if (isOllamaCloud && !string.IsNullOrEmpty(usedOllamaKey))
                                RecordOllamaKeyRequest(agentId, usedOllamaKey);
                            break;
                        }

                        // 429 Ollama Cloud Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В·Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В»Р В Р РӢР В РІРӮв„–Р В Р РӢР РҶР вҖҡР РӢ Р В Р РӢР В Р РҸР В Р’В Р РҺРІРӮСң rate-limited, Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’ВұР В Р РӢР РҺРІРӮСҡР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡР В Р’В Р РҺРІРӮвҖқР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң
                        if (isOllamaCloud && (int)resp.StatusCode == 429
                            && !string.IsNullOrEmpty(usedOllamaKey))
                        {
                            MarkOllamaKeyRateLimited(agentId, usedOllamaKey);
                            resp.Dispose();
                            resp = null;
                            continue;
                        }

                        // Р В Р’В Р РҶР вҖҡР’В Р В Р’В Р В РІРӮВҰР В Р РӢР РҶРІРӮСҷР’В¬Р В Р’В Р вҖҷР’В° non-2xx Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’ВұР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’ВұР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В¶Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’Вө
                        break;
                    }

                    if (resp == null || !resp.IsSuccessStatusCode)
                    {
                        // Tools fallback: 500 Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳ ollama-cloud Р В Р вҖ Р РҶР вҖҡР’В Р РҶР вҖҡРІвҖһСһ Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ° Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺР’ВҳР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎСҡ tool calling, Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р РӢР В РІРӮв„–Р В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В· tools
                        if (resp != null && (int)resp.StatusCode == 500 && isOllamaCloud && useTools && !toolsFailedFallback)
                        {
                            toolsFailedFallback = true;
                            resp.Dispose();
                            continue;
                        }

                        // Image fallback: Р В Р РӢР В Р РҸР В Р’В Р В РІРӮВ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһ Р В Р’В Р вҖҷР’В·Р В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’ВұР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р В РІРӮВҰР В Р РӢР В Р РҸ Р В Р вҖ Р РҶР вҖҡР’В Р РҶР вҖҡРІвҖһСһ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸР В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ° Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡР’ВҰР В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһ retry
                        if (resp != null && imageHistoryIdx >= 0
                            && ((int)resp.StatusCode == 400 || (int)resp.StatusCode == 500))
                        {
                            var errBody = await resp.Content.ReadAsStringAsync(ct);
                            var isImageErr = errBody.Contains("image", StringComparison.OrdinalIgnoreCase)
                                          || errBody.Contains("multimodal", StringComparison.OrdinalIgnoreCase)
                                          || errBody.Contains("vision", StringComparison.OrdinalIgnoreCase)
                                          || errBody.Contains("unsupported", StringComparison.OrdinalIgnoreCase);
                            if (isImageErr)
                            {
                                if (TrySwitchToFallbackVisionModel(
                                        isOllamaCloud,
                                        targetModel,
                                        ref visionFallbackTried,
                                        out visionModelOverride))
                                {
                                    RecordLlmFailure(diagProvider, targetModel, diagChannel, (int)resp.StatusCode, errBody, diagWatch, "vision_fallback_retry");
                                    resp.Dispose();
                                    continue;
                                }

                                lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                                RecordLlmFailure(diagProvider, diagModel, diagChannel, (int)resp.StatusCode, errBody, diagWatch, "vision_rejected");
                                return BuildVisionUnavailableReply(userText);
                            }
