                                var type = item["type"]?.ToString();
                                if (type == "tool_use")
                                {
                                    claudeToolCalls.Add(new JObject
                                    {
                                        ["id"] = item["id"]?.ToString() ?? Guid.NewGuid().ToString("N")[..8],
                                        ["type"] = "function",
                                        ["function"] = new JObject
                                        {
                                            ["name"] = item["name"]?.ToString() ?? "",
                                            ["arguments"] = JsonConvert.SerializeObject(item["input"] ?? new JObject())
                                        }
                                    });
                                }
                                else if (type == "text")
                                {
                                    textContent += item["text"]?.ToString() ?? "";
                                }
                            }
                        }

                        message = new JObject
                        {
                            ["role"] = role,
                            ["content"] = textContent,
                            ["tool_calls"] = claudeToolCalls.Count > 0 ? (JToken?)claudeToolCalls : null
                        };
                    }
                    else
                    {
                        // OpenAI/LM Studio format
                        message = respObj["choices"]?[0]?["message"] as JObject;
                    }

                    if (message == null) break;

                    var toolCalls = message["tool_calls"] as JArray;

                    // Fallback: some local models (Gemma/Llama) don't emit tool_calls JSON
                    // but instead embed tool call JSON blocks in plain text
                    // Gemma-4 puts response in reasoning_content when content is empty or "null"
                    var rawContent = message["content"]?.ToString() ?? "";
                    var reasoningContent = message["reasoning_content"]?.ToString() ?? "";
                    var finishReason = respObj["choices"]?[0]?["finish_reason"]?.ToString() ?? "";
                    bool truncatedShort = finishReason == "length"
                        && reasoningContent.Length > 200
                        && rawContent.Trim().Length < 40;
                    if (string.IsNullOrWhiteSpace(rawContent)
                        || rawContent.Trim().Equals("null", StringComparison.OrdinalIgnoreCase)
                        || truncatedShort)
                    {
                        rawContent = ExtractResponseFromReasoning(reasoningContent);
                        if (!string.IsNullOrWhiteSpace(rawContent))
                            Debug.WriteLine($"[LlmService] Extracted {rawContent.Length} chars from reasoning_content");
                        else
                            Debug.WriteLine("[LlmService] reasoning_content had no extractable response");
                    }

                    if ((toolCalls == null || toolCalls.Count == 0) && Obsidian != null)
                        toolCalls = TryParseTextToolCalls(rawContent);

                    if (!string.IsNullOrWhiteSpace(reasoningContent))
                    {
                        OnProgress?.Invoke("thought", reasoningContent);
                    }

                    // No tool calls Р В Р вҖ Р РҶР вҖҡР’В Р РҶР вҖҡРІвҖһСһ final answer
                    if (toolCalls == null || toolCalls.Count == 0)
                    {
                        if (looksLikeVaultOp && !forceNoTools)
                        {
                            lock (_histLock)
                            {
                                _history.Add(new HistoryEntry(
                                    "user",
                                    "SYSTEM CHECK: This request requires a real Obsidian tool call. Do not answer in prose. Use the correct tool now, then verify the result."));
                            }
                            continue;
                        }

                        var reply = CleanGarbage(rawContent);
                        lock (_histLock)
                        {
                            // Р В Р’В Р РҶР вҖҡРІРӮСңР В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р РӢР В РІРӮв„–Р В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ image_url entry Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° text-only Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р СһРІРӮВҳ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р В РІРӮВҰР В Р РӢР В Р РҸР В Р’В Р РҺР’Вҳ Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡ
                            if (imageHistoryIdx >= 0 && imageHistoryIdx < _history.Count)
                                _history[imageHistoryIdx] = new HistoryEntry("user", imageTextFallback);

                            _history.Add(new HistoryEntry("assistant", reply));

                            // Truncate history if exceeds limit
                            if (_history.Count > MAX_HISTORY_ENTRIES)
                                _history.RemoveRange(0, HISTORY_TRUNCATE_STEP);
                        }
                        RecordLlmSuccess(diagProvider, diagModel, diagChannel, diagWatch);
                        return reply;
                    }

                    // Store assistant message with tool_calls
                    lock (_histLock) { _history.Add(new HistoryEntry("assistant_tool_calls", message.ToString())); }

                    // Execute each tool call
                    foreach (var call in toolCalls)
                    {
                        var callId   = call["id"]?.ToString() ?? Guid.NewGuid().ToString();
                        var funcName = call["function"]?["name"]?.ToString() ?? "";
                        var argsRaw  = call["function"]?["arguments"]?.ToString() ?? "{}";
                        JObject args;
                        try { args = JObject.Parse(argsRaw); }
                        catch { args = new JObject(); }

                        System.Diagnostics.Debug.WriteLine($"[LlmService] Round {round}: tool={funcName} args={argsRaw[..Math.Min(200, argsRaw.Length)]}");
                        OnProgress?.Invoke("tool", $"Р В Р’В Р РҶР вҖҡРІвҖһСһР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡР В Р РӢР В РІРӮв„– {funcName}...");

                        var result = await ExecuteToolAsync(funcName, args, ct).ConfigureAwait(false);

                        lock (_histLock) { _history.Add(new HistoryEntry("tool", result, ToolCallId: callId, Name: funcName)); }
                    }
                }

                // Loop exhausted Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ rollback to checkpoint
                lock (_histLock)
                {
                    while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1);
                }
                RecordLlmFailure(diagProvider, diagModel, diagChannel, null, "tool loop exhausted", diagWatch, "tool_loop");
                return "[Kokonoe]: Р В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р РӢР В Р вҖ° Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶРІРӮСҷР’В¬Р В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮСң Р В Р’В Р вҖҷР’В· Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р РӢР РҺРІРӮСҡР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳ.";
            }
            catch (OperationCanceledException)
            {
                // Rollback to checkpoint
                lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                RecordLlmFailure(diagProvider, diagModel, diagChannel, null, "cancelled", diagWatch, "cancelled");
                return "[Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ]";
            }
            catch (Exception ex)
            {
                // Rollback to checkpoint
                lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                System.Diagnostics.Debug.WriteLine($"[LlmService] {ex}");
                RecordLlmFailure(diagProvider, diagModel, diagChannel, null, ex.Message, diagWatch, "exception");
                return $"[Р В Р’В Р РҺРЎСҹР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°]: {ex.Message}";
            }
        }

        // Р В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷ Build messages list for API Р В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷ

        private static bool IsTransientServerError(int statusCode)
        {
            return statusCode == 500 || statusCode == 502 || statusCode == 503 || statusCode == 504;
        }

        private static string BuildCompactSystemContent()
        {
            return "You are Kokonoe Mercury from BlazBlue. Stay in character: blunt, dry, sharp, impatient, but useful. " +
                   "Reply only in Ukrainian unless the user explicitly asks otherwise. Do not mention being an AI, model, or program. " +
                   "Give the direct answer first. Keep it concise unless the user asks for detail.";
        }

        private static string BuildFriendlyLlmError(int statusCode, string rawError, string provider)
        {
            var shortError = string.IsNullOrWhiteSpace(rawError)
                ? "no response body"
                : rawError.Trim().Replace("\r", " ").Replace("\n", " ");
            if (shortError.Length > 180)
                shortError = shortError[..180] + "...";

            if (IsTransientServerError(statusCode))
                return $"Р В Р’В Р В Р вҖ№Р В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷ Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В»Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВ  Р В Р’В Р вҖҷР’В· HTTP {statusCode}. Р В Р’В Р РҺРЎСҷР В Р РӢР РҶР вҖҡРІРӮСҡ, Р В Р РӢР РҶР вҖҡР’В Р В Р’В Р вҖҷР’Вө Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВ Р В Р РӢР В РЎвҖңР В Р РӢР В Р РҸ, Р В Р РӢР РҶР вҖҡР’В Р В Р’В Р вҖҷР’Вө {provider} Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВ Р В Р РӢР В РЎвҖңР В Р РӢР В Р РҸ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’Вҳ. Р В Р’В Р В РІРӮРҺ Р В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’Вө Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’ВұР В Р РӢР РҺРІРӮСҡР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В° Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮвҖңР В Р РӢР РҶРІРӮСҷР’В¬Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң fallback; Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р РӢР РҶРІРӮСҷР’В¬Р В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСһ. Р В Р’В Р РҺРЎСҹР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ў Р В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’ВұР В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСңР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳ Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ° Р В Р РӢР РҺРІРӮСҡ Settings. Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р вҖҷР’ВөР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°: {shortError}";

            if (statusCode == 429)
