        /// Р В Р’В Р В РІРӮВ  Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРЎв„ў Р В Р РӢР В Р РҸР В Р’В Р РҺРІРӮСң Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСңР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ў, Р В Р РӢР РҶР вҖҡР’В Р В Р’В Р вҖҷР’Вө Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎСҡ "Channel Error" Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р РҺРІРӮСңР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’В°Р В Р РӢР РҶРІРӮСҷР’В¬Р В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ° Р В Р’В Р РҺРІРӮвҖңР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР’В Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РІРӮв„–.
        /// </summary>
        private static string SanitizeContent(string text)
        {
            if (string.IsNullOrEmpty(text)) return text;
            text = RepairMojibake(text);
            var original = text;

            // Gemma/Llama special tokens: <|channel|>, <|end|>, <start_of_turn>, etc.
            text = System.Text.RegularExpressions.Regex.Replace(text, @"<\|[^>]*\|?>", "");
            text = System.Text.RegularExpressions.Regex.Replace(text, @"<(start|end)_of_(turn|text|image)>", "");

            // Control characters (Р В Р’В Р РҺРІРӮСңР В Р РӢР В РІРӮСҷР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҺР’Вҳ \n \r \t)
            text = System.Text.RegularExpressions.Regex.Replace(text, @"[\x00-\x08\x0B\x0C\x0E-\x1F]", "");

            if (text.Length < original.Length)
            {
                Debug.WriteLine($"[SanitizeContent] Removed {original.Length - text.Length} chars of special tokens");
            }
            return text;
        }

        // Р В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷ Execute Obsidian tool Р В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷ

        private async Task<string> ExecuteToolAsync(string name, JObject args, CancellationToken ct)
        {
            ct.ThrowIfCancellationRequested();

            try
            {
                if (name == "execute_python")
                {
                    return await new KokoSandboxExecutor(Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "kokonoe-data", "agent-runtime-sandbox"))
                        .ExecutePythonAsync(Req(args, "code"), ct: ct)
                        .ConfigureAwait(false);
                }

                if (name is "fs_read_text" or "fs_write_text" or "fs_delete")
                    return await ExecuteFileToolAsync(name, args, ct).ConfigureAwait(false);

                return await Task.Run(() => ExecuteTool(name, args), ct).ConfigureAwait(false);
            }
            catch (Exception ex)
            {
                return $"Tool error {name}: {ex.Message}";
            }
        }

        private string ExecuteTool(string name, JObject args)
        {
            if (name == "execute_python")
                return new KokoSandboxExecutor(Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "kokonoe-data", "agent-runtime-sandbox"))
                    .ExecutePythonAsync(Req(args, "code")).GetAwaiter().GetResult();

            if (name is "fs_read_text" or "fs_write_text" or "fs_delete")
                return ExecuteFileTool(name, args);
            if (Obsidian == null) return "Obsidian Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В»Р В Р РӢР В РІРӮв„–Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң.";

            try
            {
                return name switch
                {
                    "execute_python" => new KokoSandboxExecutor(Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "kokonoe-data", "agent-runtime-sandbox"))
                        .ExecutePythonAsync(Req(args, "code")).GetAwaiter().GetResult(),

                    "fs_read_text" => ExecuteFileTool(name, args),
                    "fs_write_text" => ExecuteFileTool(name, args),
                    "fs_delete" => ExecuteFileTool(name, args),

                    "list_notes" => FormatList(
                        Obsidian.ListNotes(args["subfolder"]?.ToString())),

                    "list_folders" => FormatList(Obsidian.ListFolders()),

                    "read_note" => Obsidian.ReadNote(Req(args, "path"))
                                   ?? $"Р В Р’В Р РҺРЎСҷР В Р’В Р РҺРІРӮСһР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р вҖҷР’В·Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°: {args["path"]}",

                    "write_note" => WriteAndLink(
                        () => Obsidian.WriteNote(Req(args, "path"), Req(args, "content")),
                        "Р В Р’В Р РҶР вҖҡРІРӮСңР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ"),

                    "create_note" => WriteAndLink(
                        () => Obsidian.CreateNote(
                            Req(args, "title"),
                            args["content"]?.ToString() ?? "",
                            args["folder"]?.ToString(),
                            args["tags"]?.ToObject<string[]>()),
                        "Р В Р’В Р В Р вҖ№Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ"),

                    "append_to_note" => WriteAndLink(
                        () => Obsidian.AppendToNote(Req(args, "path"), Req(args, "content")),
                        "Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ"),

                    "delete_note" => Delete(args),

                    "search_notes" => FormatSearch(
                        Obsidian.SearchNotes(
                            Req(args, "query"),
                            args["max"]?.Value<int>() ?? 10)),

                    "get_daily_note" => Obsidian.GetOrCreateDailyNote(),

                    "append_to_daily_note" => WriteAndLink(
                        () => Obsidian.AppendToDailyNote(Req(args, "content")),
                        "Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһ Р В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°"),

                    "rebuild_links" => RebuildLinks(),

                    "get_outgoing_links" => FormatList(
                        Obsidian.GetOutgoingLinks(Req(args, "path"))),

                    "get_backlinks" => FormatList(
                        Obsidian.GetBacklinks(Req(args, "path"))),

                    "vault_status" => Obsidian.GetVaultStatus().ToString(),

                    "cleanup_empty_notes" => FormatList(
                        Obsidian.CleanupEmptyNotes(
                            args["dry_run"]?.Value<bool>() ?? false)
                        .Select(p => (args["dry_run"]?.Value<bool>() ?? false ? "[Р В Р РӢР В РЎвҖңР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡР’ВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҺРІРӮСҡР В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСң] " : "Р В Р вҖ Р РҺРЎв„ўР РҶР вҖҡРЎСҷ Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ: ") + p)
                        .ToList()),

                    "cleanup_memory_duplicates" => Obsidian
                        .CleanupDuplicateMemoryItems(args["dry_run"]?.Value<bool>() ?? true)
                        .ToString(),

                    "init_brain_vault" => Obsidian.GetVaultInitStatus().ToString(),

                    "maintain_vault_architecture" => Obsidian
                        .MaintainKokonoeVaultArchitecture(args["reason"]?.ToString() ?? "tool-call")
                        .ToString(),

                    "get_vault_tree" => Obsidian.GetVaultTree(),

                    "move_note" => Obsidian.MoveNote(
                        Req(args, "old_path"), Req(args, "new_path")),

                    "create_folder" => CreateFolderVerified(Req(args, "folder_path")),

                    "save_architecture_plan" => SaveArchitecturePlan(Req(args, "plan")),

                    _ => $"Р В Р’В Р РҺРЎСҷР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р РӢР РҺРІРӮСҡР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРЎв„ў: {name}"
                };
            }
            catch (Exception ex)
            {
                return $"Р В Р’В Р РҺРЎСҹР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳ Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ {name}: {ex.Message}";
            }
        }

        private static string Req(JObject args, string key) =>
            args[key]?.ToString() ?? throw new ArgumentException($"Р В Р’В Р РҶР вҖҡРІвҖһСһР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР В РЎвҖңР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В°Р В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’ВөР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷ: {key}");

        private static string ExecuteFileTool(string name, JObject args)
            => ExecuteFileToolAsync(name, args, CancellationToken.None).GetAwaiter().GetResult();

        private static async Task<string> ExecuteFileToolAsync(string name, JObject args, CancellationToken ct)
        {
            var kind = name switch
            {
                "fs_read_text" => KokoFileOperationKind.ReadText,
                "fs_write_text" => KokoFileOperationKind.WriteText,
                "fs_delete" => KokoFileOperationKind.Delete,
                _ => throw new ArgumentException($"Unknown file tool: {name}")
            };

            var request = new KokoFileOperationRequest
            {
                Kind = kind,
                Path = Req(args, "path"),
                Content = args["content"]?.ToString() ?? "",
                Confirmed = args["confirmed"]?.Value<bool>() ?? false
            };
            var result = await ServiceContainer.FileTools.ExecuteAsync(request, ct).ConfigureAwait(false);
            var confirmation = result.RequiresConfirmation ? " confirmation_required=true" : "";
            return $"{(result.Success ? "ok" : "failed")}:{confirmation} {result.Message}\n{result.Output}".Trim();
        }

        private static string FormatList(List<string> items) =>
            items.Count == 0 ? "(Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р’В Р В РІРӮВҰР В Р РӢР В Р вҖ°Р В Р’В Р РҺРІРӮСһ)" : string.Join("\n", items);

        private static string FormatSearch(List<SearchResult> results) =>
            results.Count == 0
                ? "Р В Р’В Р РҺРЎСҷР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡР РӢР В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р вҖҷР’В·Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ."
                : string.Join("\n\n", results.Select(r =>
                    $"Р РҺР вҖҡР РҺРЎСҹР РҶР вҖҡРЎСҷР РҶР вҖҡРЎвҖә {r.Path} [score:{r.Score}]\n{r.Preview[..Math.Min(200, r.Preview.Length)]}"));

        private static string WrapOk(string path, string label) =>
            $"Р В Р вҖ Р РҺРЎв„ўР РҶР вҖҡРЎСҷ {label}: {path}";

        private string Delete(JObject args)
        {
            var path = Req(args, "path");
            Obsidian!.DeleteNote(path);
            return $"Р В Р вҖ Р РҺРЎв„ўР РҶР вҖҡРЎСҷ Р В Р’В Р РҶР вҖҡРІвҖһСһР В Р’В Р РҺРІРӮВҳР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ: {path}";
        }

        private string RebuildLinks()
        {
            var (changed, added) = Obsidian!.RebuildLinks();
            return $"Р В Р вҖ Р РҺРЎв„ўР РҶР вҖҡРЎСҷ Р В Р’В Р РҺРІРӮС”Р В Р’В Р вҖҷР’ВұР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ Р В Р РӢР РҶР вҖҡРЎвҖәР В Р’В Р вҖҷР’В°Р В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р вҖҷР’В»Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВ : {changed}, Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р РӢР В Р вҖ°: {added}.";
        }

        private string CreateFolderVerified(string folderPath)
        {
            Obsidian!.CreateFolder(folderPath);
            var full = Path.Combine(Obsidian.VaultPath, folderPath.Replace('/', Path.DirectorySeparatorChar));
            return Directory.Exists(full)
                ? $"Р В Р вҖ Р РҺРЎв„ўР РҶР вҖҡРЎСҷ Р В Р’В Р В Р вҖ№Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ: {folderPath}"
                : $"Р В Р вҖ Р РҺРЎСҷР В Р вҖ° Р В Р’В Р РҺРЎСҹР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ: {folderPath}";
        }

        private string SaveArchitecturePlan(string plan)
        {
            const string planPath = "Core/Architecture-Plans.md";
            var entry = $"\n\n## {DateTime.Now:dd.MM.yyyy HH:mm}\n{plan}";
            var existing = Obsidian!.ReadNote(planPath);
            if (existing == null)
            {
                Obsidian.WriteNote(planPath,
                    $"---\ntype: architecture-plans\ntags: [kokonoe, architecture]\ncreated: {DateTime.Now:yyyy-MM-dd}\n---\n\n# Р В Р’В Р РҺРІРӮв„ўР В Р РӢР В РІРӮСҷР В Р РӢР РҶР вҖҡР’ВҰР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡР В Р РӢР В РІРӮСҷР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳ\n\nР В Р’В Р РҺРЎСҹР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳ Р В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮвҖңР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР’В Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡРІРӮСң vault.{entry}");
            }
            else
            {
                Obsidian.AppendToNote(planPath, entry);
            }
            return $"Р В Р вҖ Р РҺРЎв„ўР РҶР вҖҡРЎСҷ Р В Р’В Р РҺРЎСҹР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ: {planPath}";
        }

