        /// Р В Р’В Р РҶР вҖҡРІРӮСңР В Р’В Р В РІРӮВ 'Р В Р РӢР В Р РҸР В Р’В Р вҖҷР’В·Р В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮВҳ Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸР В Р РӢР В РІРӮв„–Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ°Р В Р РӢР В РЎвҖңР В Р РӢР В Р РҸ Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В· Р В Р’В Р вҖҷР’ВұР В Р РӢР РҺРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР В Р вҖ°-Р В Р РӢР В Р РҸР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р СһРІРӮВҳ Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳ Р В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’В°.
        /// </summary>
        // Р В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷ Fallback text-based tool call parser Р В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷ
        // Handles local models (Gemma, Llama) that don't output proper tool_calls JSON.
        // Looks for JSON blocks like: {"name":"create_note","arguments":{...}}
        // or {"tool":"create_note","parameters":{...}} embedded in model output.
        // Also handles Gemma-4 backtick style: `write_note(path="...", content="...")`
        private static readonly string[] _knownToolNames = {
            "write_note", "create_note", "append_to_note", "append_to_daily_note",
            "read_note", "list_notes", "list_folders", "delete_note", "search_notes",
            "get_daily_note", "rebuild_links", "vault_status", "cleanup_empty_notes", "cleanup_memory_duplicates",
            "init_brain_vault", "maintain_vault_architecture", "get_outgoing_links", "get_backlinks",
            "get_vault_tree", "move_note", "create_folder", "save_architecture_plan"
        };

        private static JArray? TryParseTextToolCalls(string content)
        {
            if (string.IsNullOrWhiteSpace(content)) return null;

            var calls = new JArray();

            // Pattern 1: {"name":"tool_name","arguments":{...}}
            // Pattern 2: {"tool":"tool_name","parameters":{...}}
            var jsonMatches = System.Text.RegularExpressions.Regex.Matches(
                content, @"\{[^{}]*""(?:name|tool)""\s*:\s*""(\w+)""[^{}]*\{.*?\}[^{}]*\}",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            foreach (System.Text.RegularExpressions.Match m in jsonMatches)
            {
                try
                {
                    var obj = JObject.Parse(m.Value);
                    var toolName = obj["name"]?.ToString() ?? obj["tool"]?.ToString();
                    if (string.IsNullOrEmpty(toolName)) continue;

                    var argsObj = obj["arguments"] ?? obj["parameters"] ?? obj["args"] ?? new JObject();

                    calls.Add(JObject.FromObject(new
                    {
                        id       = Guid.NewGuid().ToString("N")[..8],
                        type     = "function",
                        function = new { name = toolName, arguments = argsObj.ToString() }
                    }));
                }
                catch { /* ignore malformed JSON */ }
            }

            // Pattern 3: <tool_call>{"name":"...","arguments":{...}}</tool_call>
            var xmlMatches = System.Text.RegularExpressions.Regex.Matches(
                content, @"<tool_call>\s*(\{.*?\})\s*</tool_call>",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            foreach (System.Text.RegularExpressions.Match m in xmlMatches)
            {
                try
                {
                    var obj      = JObject.Parse(m.Groups[1].Value);
                    var toolName = obj["name"]?.ToString() ?? obj["tool"]?.ToString();
                    if (string.IsNullOrEmpty(toolName)) continue;

                    var argsObj = obj["arguments"] ?? obj["parameters"] ?? new JObject();

                    calls.Add(JObject.FromObject(new
                    {
                        id       = Guid.NewGuid().ToString("N")[..8],
                        type     = "function",
                        function = new { name = toolName, arguments = argsObj.ToString() }
                    }));
                }
                catch { }
            }

            // Pattern 4: Gemma-4 backtick/bare function call Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ `write_note(key="val", ...)` or write_note(key="val")
            // Uses balanced-paren + string-aware walking so nested parens/quotes inside content="..." work correctly.
            foreach (var toolName in _knownToolNames)
            {
                var searchStr = toolName + "(";
                var startIdx  = content.IndexOf(searchStr, StringComparison.Ordinal);
                if (startIdx < 0) continue;

                var argsStart = startIdx + searchStr.Length;

                // Walk forward counting parens, respecting string literals
                int depth     = 1;
                int idx       = argsStart;
                bool inStr    = false;
                char strCh    = '"';

                while (idx < content.Length && depth > 0)
                {
                    char c = content[idx];
                    if (inStr)
                    {
                        if (c == '\\')          idx++;          // skip escape sequence
                        else if (c == strCh)    inStr = false;
                    }
                    else
                    {
                        if      (c == '"' || c == '\'') { inStr = true; strCh = c; }
                        else if (c == '(')  depth++;
                        else if (c == ')')  depth--;
                    }
                    if (depth > 0) idx++;
                }

                if (depth != 0) continue; // unmatched parens Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ skip

                var argsStr = content[argsStart..idx];

                // Parse key="value" pairs (handles \n \t \" \\ escapes)
                var argsObj   = new JObject();
                var argPairs  = System.Text.RegularExpressions.Regex.Matches(
                    argsStr, "(?s)(\\w+)=\"((?:[^\"\\\\]|\\\\.)*)\"");
                foreach (System.Text.RegularExpressions.Match am in argPairs)
                {
                    argsObj[am.Groups[1].Value] = am.Groups[2].Value
                        .Replace("\\n",  "\n")
                        .Replace("\\t",  "\t")
                        .Replace("\\\"", "\"")
                        .Replace("\\\\", "\\");
                }

                // Fallback: bare unquoted values like dry_run=true
                if (!argsObj.HasValues)
                {
                    var simplePairs = System.Text.RegularExpressions.Regex.Matches(argsStr, @"(\w+)=(\S+)");
                    foreach (System.Text.RegularExpressions.Match am in simplePairs)
                        argsObj[am.Groups[1].Value] = am.Groups[2].Value;
                }

                calls.Add(JObject.FromObject(new
                {
                    id       = Guid.NewGuid().ToString("N")[..8],
                    type     = "function",
                    function = new { name = toolName, arguments = argsObj.ToString() }
                }));

                System.Diagnostics.Debug.WriteLine(
                    $"[LlmService] Backtick tool call: {toolName}({argsStr[..Math.Min(80, argsStr.Length)]})");
            }

            // Pattern 5: Anthropic-style XML Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ <invoke name="X"><parameter name="Y">val</parameter>...</invoke>
            // (gpt-oss Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р вҖҷР’ВұР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В»Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р вҖҷР’В»Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ° Р В Р РӢР РҶР вҖҡР’В Р В Р’В Р вҖҷР’ВөР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р РӢР РҶР вҖҡРЎвҖәР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ў Р В Р’В Р вҖҷР’В· training data Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ° tool_calls API)
            var invokeMatches = System.Text.RegularExpressions.Regex.Matches(
                content,
                @"<invoke\s+name=""(\w+)""\s*>(.*?)</invoke>",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            foreach (System.Text.RegularExpressions.Match m in invokeMatches)
            {
                var toolName = m.Groups[1].Value;
                var inner    = m.Groups[2].Value;
                if (string.IsNullOrEmpty(toolName)) continue;

                var argsObj = new JObject();
                var paramMatches = System.Text.RegularExpressions.Regex.Matches(
                    inner,
                    @"<parameter\s+name=""(\w+)""\s*>(.*?)</parameter>",
                    System.Text.RegularExpressions.RegexOptions.Singleline);

                foreach (System.Text.RegularExpressions.Match pm in paramMatches)
                    argsObj[pm.Groups[1].Value] = pm.Groups[2].Value;

                calls.Add(JObject.FromObject(new
                {
                    id       = Guid.NewGuid().ToString("N")[..8],
                    type     = "function",
                    function = new { name = toolName, arguments = argsObj.ToString() }
                }));

                System.Diagnostics.Debug.WriteLine(
                    $"[LlmService] <invoke> tool call: {toolName} with {argsObj.Count} params");
            }

            return calls.Count > 0 ? calls : null;
        }

        // Р В Р’В Р РҶР вҖҡРІвҖһСһР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В·Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎСҡ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р вҖҷР’ВұР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°Р В Р РӢР РҶРІРӮСҷР’В¬ Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡР’ВҰР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р РӢР В Р РҸР В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р РӢР РҺРІРӮСҡР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРЎв„ў Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСңР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡ
        private static string DetectBestTool(string text)
        {
            var t = RepairMojibake(text).ToLowerInvariant();
            if ((t.Contains("\u0441\u043f\u0438\u0441") || t.Contains("list")) && (t.Contains("\u043d\u043e\u0442\u0430\u0442") || t.Contains("note")))
                return "list_notes";
            if ((t.Contains("\u0441\u043f\u0438\u0441") || t.Contains("list")) && (t.Contains("\u043f\u0430\u043f") || t.Contains("folder")))
                return "list_folders";
            if (t.Contains("\u0441\u043f\u0438\u0441\u043e\u043a \u043f\u0430\u043f") || t.Contains("\u044f\u043a\u0456 \u043f\u0430\u043f\u043a") || t.Contains("list folders"))
                return "list_folders";
            if (t.Contains("\u0441\u043f\u0438\u0441\u043e\u043a \u043d\u043e\u0442\u0430\u0442") || t.Contains("\u044f\u043a\u0456 \u043d\u043e\u0442\u0430\u0442\u043a\u0438") || t.Contains("list notes"))
                return "list_notes";
            if ((t.Contains("\u0441\u0442\u0432\u043e\u0440") || t.Contains("\u043d\u043e\u0432\u0430") || t.Contains("\u043d\u043e\u0432\u0443") || t.Contains("new") || t.Contains("create")) &&
                (t.Contains("\u043f\u0430\u043f\u043a") || t.Contains("folder")))
                return "create_folder";
            if (t.Contains("\u0449\u043e\u0434\u0435\u043d\u043d\u0438\u043a") || t.Contains("daily"))
                return "append_to_daily_note";
            if (t.Contains("\u0437\u043d\u0430\u0439\u0434") || t.Contains("\u043f\u043e\u0448\u0443\u043a") || t.Contains("search"))
                return "search_notes";
            if (t.Contains("\u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0439") || t.Contains("\u043f\u043e\u043a\u0430\u0436\u0438") || t.Contains("\u0432\u0456\u0434\u043a\u0440\u0438\u0439"))
                return "read_note";
            if (t.Contains("\u043d\u043e\u0432\u0443 \u043d\u043e\u0442\u0430\u0442\u043a") || t.Contains("\u0441\u0442\u0432\u043e\u0440\u0438 \u043d\u043e\u0442\u0430\u0442\u043a"))
                return "create_note";
            return "append_to_note";
        }

        // Remove model-generated garbage tokens that leak into visible output
        private static string CleanGarbage(string text)
        {
            if (string.IsNullOrEmpty(text)) return "...";
            var originalLength = text.Length;
            text = RepairMojibake(text);

            // Remove <think>...</think> blocks from reasoning models
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?s)<think>.*?</think>", "",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            // Remove <|tool_response>...<|> style tokens
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"<\|tool_response\>.*?(\}|\)|\>|$)", "",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            // Remove <tool_call>...</tool_call> blocks that were text-parsed above
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?s)<tool_call>.*?</tool_call>", "",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            // Remove Anthropic-style <invoke name="X">...</invoke> blocks (parsed as tools above)
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?s)<invoke\s+name=""[^""]+""\s*>.*?</invoke>", "",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            // Remove orphan opening tags that leaked from training data:
            // <function_calls>, <function_calls>, <invoke ...>, <parameter ...>
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"<(?:antml:)?function_calls\s*>", "",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"<invoke\s+name=""[^""]*""\s*>", "");
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"<parameter\s+name=""[^""]*""\s*>", "");

            // Remove orphan closing tags that the model leaks from training (HTML/XML junk):
            // </textarea>, </brain>, </invoke>, </parameter>, </function_calls>
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"</(?:textarea|brain|invoke|parameter|(?:antml:)?function_calls)>", "",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);

            // Remove bare JSON tool call objects that start with {"name":"...
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?s)\{""(?:name|tool)""\s*:\s*""\w+""\s*,.*?\}\s*\}",
                "", System.Text.RegularExpressions.RegexOptions.Singleline);

            // Remove Gemma-4 backtick function calls that were text-parsed above:
            // `write_note(path="...", content="...")` Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ strip so user never sees raw tool call
            foreach (var tn in _knownToolNames)
            {
                // Strip backtick-wrapped calls: `tool_name(...)` using a greedy quoted-string aware pattern
                text = System.Text.RegularExpressions.Regex.Replace(
                    text,
                    "`" + System.Text.RegularExpressions.Regex.Escape(tn) + @"\((?:[^""'`]|""[^""]*""|'[^']*')*\)`",
                    "",
                    System.Text.RegularExpressions.RegexOptions.Singleline);

                // Strip bare calls (no backticks): tool_name(...)
                text = System.Text.RegularExpressions.Regex.Replace(
                    text,
                    @"\b" + System.Text.RegularExpressions.Regex.Escape(tn) + @"\((?:[^""'`\n]|""[^""]*""|'[^']*')*\)",
                    "",
                    System.Text.RegularExpressions.RegexOptions.Singleline);
            }

            // Remove leftover special tokens: <|token|> and <|token>
            text = System.Text.RegularExpressions.Regex.Replace(text, @"<\|[^|>\s]*\|?>", "");

            // Also strip starting markdown blocks or thought blocks that don't have closing tags or start with * Thought:
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?s)^\s*\*[^\n]*Thought:.*?\n\n", "",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            // Remove Gemma-4 internal reasoning patterns (when reasoning_content has analysis)
            // "Kokonoe Mercury." header with timestamp
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?s)^\s*Kokonoe Mercury\.\s*\d{2}:\d{2}.*?\n", "",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            // "Option X:" lines (analysis of different response options)
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?m)^\s*\*\s*Option \d+:.*?$", "",
                System.Text.RegularExpressions.RegexOptions.Multiline);

            // "Draft X:" labels
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?m)^\s*\*\s*Draft \d+:.*?$", "",
                System.Text.RegularExpressions.RegexOptions.Multiline);

            // "Self-Correction:" blocks
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?m)^\s*\*\s*Self-Correction:.*?$", "",
                System.Text.RegularExpressions.RegexOptions.Multiline);

            // "Language:", "Tone:", "Content:" labels
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?m)^\s*\*\s*(Language|Tone|Content):.*?$", "",
                System.Text.RegularExpressions.RegexOptions.Multiline);

            // Personality/Relationship/Response Style analysis
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?m)^\s*\*\s*(Personality|Relationship|Response Style|Does she know\?|How would she react\?):.*?$", "",
                System.Text.RegularExpressions.RegexOptions.Multiline);

            // Context/Internal Data Check sections
            text = System.Text.RegularExpressions.Regex.Replace(
                text, @"(?s)\*\s*Context/Internal Data Check:.*?\n\s*\*\s*Current Date:", "",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            // Remove empty lines that might be left after filtering
            text = System.Text.RegularExpressions.Regex.Replace(text, @"\n{3,}", "\n\n");

            var result = text.Trim();
            if (result.Length == 0)
            {
                Debug.WriteLine("[CleanGarbage] Warning: result is empty after cleaning, returning '...'");
                return "...";
            }
            if (result.Length < originalLength)
            {
                Debug.WriteLine($"[CleanGarbage] Removed {originalLength - result.Length} chars (was {originalLength}, now {result.Length})");
            }
            return result;
        }

        public static string RepairMojibake(string text)
        {
            if (string.IsNullOrEmpty(text)) return text;
            text = System.Text.RegularExpressions.Regex.Replace(text, @"\uFFFD{2,}", "...");
            text = text.Replace("\uFFFD", "");
            if (!LooksLikeMojibake(text)) return text;

            try
            {
                System.Text.Encoding.RegisterProvider(System.Text.CodePagesEncodingProvider.Instance);
                var cp1251 = System.Text.Encoding.GetEncoding(1251);
                var fixedText = System.Text.Encoding.UTF8.GetString(cp1251.GetBytes(text));
                return ScoreMojibake(fixedText) < ScoreMojibake(text) ? fixedText : text;
            }
            catch
            {
                return text;
            }
        }

        private static bool LooksLikeMojibake(string text)
            => ScoreMojibake(text) >= 3;

        private static int ScoreMojibake(string text)
        {
            if (string.IsNullOrEmpty(text)) return 0;
            var score = 0;
            string[] markers =
            {
                "Р В Р’В Р вҖҷР’В Р В Р РӢР РҶР вҖҡРІвҖһСһ", "Р В Р’В Р вҖҷР’В Р В Р’В Р РҺРІРӮСҡ", "Р В Р’В Р вҖҷР’В Р В Р’В Р РҶР вҖҡРЎвҖә", "Р В Р’В Р вҖҷР’В Р В Р вҖ Р В РІРӮСҷР вҖҷР’В ", "Р В Р’В Р вҖҷР’В Р В Р’В Р РҶР вҖҡР РӢ", "Р В Р’В Р вҖҷР’В Р В РІРӮв„ўР вҖҷР’В°", "Р В Р’В Р вҖҷР’В Р В РІРӮв„ўР вҖҷР’Вө", "Р В Р’В Р вҖҷР’В Р В Р РӢР РҶР вҖҡР’Вҳ", "Р В Р’В Р вҖҷР’В Р В Р РӢР РҶР вҖҡРЎСӣ", "Р В Р’В Р вҖҷР’В Р В Р РӢР РҶР вҖҡРІРӮСң", "Р В Р’В Р вҖҷР’В Р В Р РӢР В РІРӮСҷ",
                "Р В Р’В Р В Р вҖ№Р В Р’В Р РҺРІРӮСҡ", "Р В Р’В Р В Р вҖ№Р В Р вҖ Р В РІРӮСҷР РҺРІвҖһСһ", "Р В Р’В Р В Р вҖ№Р В Р’В Р В РІРӮВ°", "Р В Р’В Р В Р вҖ№Р В Р’В Р РҶР вҖҡРІвҖһвҖ“", "Р В Р’В Р В Р вҖ№Р В Р’В Р В Р РҸ", "Р В Р’В Р В Р вҖ№Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҷ", "Р В Р’В Р В Р вҖ№Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ", "Р В Р’В Р В Р вҖ№Р В Р вҖ Р В РІРӮСҷР РҺРЎСҷ", "Р В Р’В Р В РІРӮВ Р В Р’В Р РҶР вҖҡРЎв„ў", "Р В Р’В Р В РІРӮВ Р В Р РӢР РҺРІвҖһСһ", "Р В Р РӢР В РІРӮСҷР В Р РӢР РҺРЎСҹ",
                "Р В Р’В Р РҺРЎСҹ", "Р В Р’В Р вҖҷР’Вө", "Р В Р’В Р вҖҷР’В°", "Р В Р’В Р РҺРІРӮВҳ", "Р В Р’В Р В РІРӮВҰ", "Р В Р’В Р РҺРІРӮСһ", "Р В Р’В Р РҺРІРӮСң", "Р В Р’В Р вҖҷР’В»", "Р В Р’В Р РҺР’Вҳ", "Р В Р’В Р СһРІРӮВҳ", "Р В Р РӢР В Р вҖ°", "Р В Р РӢР РҶР вҖҡРІРӮСҡ", "Р В Р РӢР В Р РҸ", "Р В Р РӢР РҶР вҖҡР’В ", "Р В Р РӢР В РІРӮв„–",
                "Р В Р вҖ Р В РІРӮСҷ", "Р В Р вҖ Р РҺРЎв„ў", "Р В РЎвҖ“Р В РІРӮСҷ", "Р вҖңРІРӮСҷ", "Р вҖңРЎвҖң"
            };
            foreach (var marker in markers)
                score += System.Text.RegularExpressions.Regex.Matches(text, System.Text.RegularExpressions.Regex.Escape(marker)).Count;
            return score;
        }
        // Р В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷР В Р вҖ Р РҶР вҖҡРЎСҡР В РІРӮСҷ

        /// <summary>
        /// Streaming variant Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ invokes onChunk for each token delta.
        /// Returns null if tool_calls detected mid-stream (caller should fall back to SendAsync).
        /// Returns full reply string on success.
        /// NOTE: Only works with LM Studio (OpenAI format). Claude API falls back to SendAsync.
        /// </summary>
        public async Task<string?> SendStreamingAsync(
            string userText,
            string? extraContext,
            Action<string> onChunk,
            CancellationToken ct = default,
            string? agentId = null)
        {
            // Claude API doesn't support streaming in this implementation yet Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ fall back to SendAsync
            var target = ResolveAgentTarget(agentId);
            if (target.Provider.Equals("claude", StringComparison.OrdinalIgnoreCase))
            {
                var reply = await SendAsync(userText, extraContext: extraContext, ct: ct, agentId: agentId);
                if (!string.IsNullOrEmpty(reply))
                    onChunk(reply);
                return reply;
            }

            // Checkpoint: Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҺРІРӮвҖңР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡРІРӮСң Р В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸ Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡ
            int checkpoint;
            lock (_histLock) { checkpoint = _history.Count; }

            lock (_histLock) { _history.Add(new HistoryEntry("user", userText)); }

            var dateStamp     = $"\n\n=== Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮв„ўР В Р’В Р РҺРЎвҖәР В Р’В Р РҺРІРӮв„ў/Р В Р’В Р вҖҷР’В§Р В Р’В Р РҺРІРӮв„ўР В Р’В Р В Р вҖ№ ===\nР В Р’В Р В Р вҖ№Р В Р РӢР В Р вҖ°Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ: {DateTime.Now:dddd, dd MMMM yyyy}, {DateTime.Now:HH:mm}";
            var screenPart    = string.IsNullOrEmpty(ScreenCtx)       ? "" : "\n\n=== Р В Р’В Р РҶР вҖҡРЎСӣР В Р’В Р РҺРІвҖһСһР В Р’В Р вҖҷР’В Р В Р’В Р РҺРІРӮв„ўР В Р’В Р РҺРЎСҷ ===\n" + ScreenCtx;
            var personPart    = string.IsNullOrEmpty(PersonalityHint) ? "" : "\n\n" + PersonalityHint;
            var contextPart   = string.IsNullOrEmpty(extraContext)    ? "" : "\n\n=== CONTEXT ===\n" + extraContext;
            var systemContent = SYSTEM_PROMPT + BuildCapabilityPrompt(agentId) + dateStamp + screenPart + personPart + contextPart;

            var looksLikeVaultOp = !string.IsNullOrEmpty(userText) && (
                userText.Contains("Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷ", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСң", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РІРӮСҷ", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РІРӮСҷ", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶРІРӮСҷР’В¬", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В¶", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСң", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("vault", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("obsidian", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСң", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’Вҳ'Р В Р РӢР В Р РҸР В Р РӢР РҶР вҖҡРЎв„ў", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһ", StringComparison.OrdinalIgnoreCase) ||
                userText.Contains("Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСң", StringComparison.OrdinalIgnoreCase));
            var useTools = Obsidian != null && looksLikeVaultOp;
            var streamIsOllamaCloud = target.Provider.Equals("ollama-cloud", StringComparison.OrdinalIgnoreCase);
            var streamUrl = target.Url;
            var streamModel = target.Model;
            object reqBody = useTools
                ? (object)new { model = streamModel, messages = BuildMessages(systemContent), tools = TOOLS,
                                tool_choice = "auto", max_tokens = MainMaxTokens, temperature = target.Temperature, stream = true }
                : new { model = streamModel, messages = BuildMessages(systemContent),
                        max_tokens = MainMaxTokens, temperature = target.Temperature, stream = true };

            var json = JsonConvert.SerializeObject(reqBody);

            // Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸ Ollama Cloud Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ retry-loop Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһ Р В Р’В Р вҖҷР’В¶Р В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В»Р В Р РӢР В РІРӮв„–Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳ 429 (Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°Р В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮВҳ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡРІРӮСң headers,
            // mid-stream retry Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’ВөР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р РӢР РҶР вҖҡР’ВҰР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡР РӢР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ).
            int ollamaAttempts = streamIsOllamaCloud ? GetOllamaAttemptCount(agentId) : 1;
            HttpResponseMessage? resp = null;
            string? usedOllamaKey = null;

            try
            {
                for (int attempt = 0; attempt < ollamaAttempts; attempt++)
                {
                    var req = new HttpRequestMessage(HttpMethod.Post, streamUrl)
                    {
                        Content = new StringContent(json, Encoding.UTF8, "application/json")
                    };
                    if (streamIsOllamaCloud)
                    {
                        usedOllamaKey = ResolveOllamaKey(agentId);
                        if (!string.IsNullOrEmpty(usedOllamaKey))
                            req.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", usedOllamaKey);
                    }

                    resp = await _http.SendAsync(req, HttpCompletionOption.ResponseHeadersRead, ct);
                    if (resp.IsSuccessStatusCode) break;

                    if (streamIsOllamaCloud && (int)resp.StatusCode == 429
                        && !string.IsNullOrEmpty(usedOllamaKey))
                    {
                        MarkOllamaKeyRateLimited(agentId, usedOllamaKey);
                        resp.Dispose();
                        resp = null;
                        continue;
                    }
                    break;
                }

                if (resp == null || !resp.IsSuccessStatusCode)
                {
                    // Rollback to checkpoint
                    lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                    return null;
                }

                var sb = new StringBuilder();
                var sbReasoning = new StringBuilder();
                using var stream = await resp.Content.ReadAsStreamAsync(ct);
                using var reader = new System.IO.StreamReader(stream);

                while (!reader.EndOfStream)
                {
                    ct.ThrowIfCancellationRequested();
                    var line = await reader.ReadLineAsync();
                    if (line == null || !line.StartsWith("data: ")) continue;
                    var data = line[6..];
                    if (data == "[DONE]") break;
                    try
                    {
                        var obj   = JObject.Parse(data);
                        var delta = obj["choices"]?[0]?["delta"];
                        if (delta?["tool_calls"] != null)
                        {
                            // Tool call detected Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ rollback to checkpoint and signal caller to use SendAsync
                            lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                            return null;
                        }
                        var chunk = delta?["content"]?.ToString();
                        if (string.IsNullOrEmpty(chunk) || chunk.Trim().Equals("null", StringComparison.OrdinalIgnoreCase))
                        {
                            // Р В Р’В Р В РІвҖҡВ¬ Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺР’ВҳР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р РҺР’ВҳР В Р РӢР РҶР вҖҡРІРӮСҡ chunks reasoning_content Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ
                            // Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎвҖәР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ "Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’ВөР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡ" Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’ВұР В Р’В Р РҺРІРӮВҳР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВ Р В Р РӢР В РЎвҖңР В Р’В Р вҖҷР’Вө Р В Р РӢР РҺРІРӮСҡ sbReasoning Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р вҖҷР’В·Р В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’ВұР В Р’В Р РҺРІРӮВҳР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ
                            // Р В Р РӢР РҶР вҖҡРЎвҖәР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°Р В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡ Р В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСңР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡР’В Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РІРӮв„– Р В Р’В Р В РІРӮВ  Р В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡР’В Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ.
                            var reasoningChunk = delta?["reasoning_content"]?.ToString();
                            if (!string.IsNullOrEmpty(reasoningChunk)) sbReasoning.Append(reasoningChunk);
                            chunk = null;
                        }
                        if (!string.IsNullOrEmpty(chunk))
                        {
                            sb.Append(chunk);
                            onChunk(chunk);
                        }
                    }
                    catch { }
                }

                var rawText = sb.ToString();

