                // Р В Р’В Р В РІРӮРҺР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ° Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р РӢР РҺРІРӮСҡР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В° tool calls Р В Р РӢР В Р РҸР В Р’В Р РҺРІРӮСң Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮСңР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ў (Gemma-Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°) Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ fall back Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһ SendAsync
                // Р В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’Вұ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р РӢР РҺРІРӮСҡР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р вҖҷР’ВұР В Р РӢР РҺРІРӮСҡР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮВҳ Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В· tool-calling loop
                if (Obsidian != null)
                {
                    var textCalls = TryParseTextToolCalls(rawText);
                    if (textCalls != null && textCalls.Count > 0)
                    {
                        // Rollback to checkpoint
                        lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                        return null; // caller falls back to SendAsync
                    }
                }

                var reply = CleanGarbage(rawText);
                if (string.IsNullOrWhiteSpace(reply))
                {
                    // Rollback to checkpoint
                    lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                    return null;
                }

                lock (_histLock)
                {
                    _history.Add(new HistoryEntry("assistant", reply));
                    if (_history.Count > MAX_HISTORY_ENTRIES) _history.RemoveRange(0, HISTORY_TRUNCATE_STEP);
                }
                if (streamIsOllamaCloud && !string.IsNullOrEmpty(usedOllamaKey))
                    RecordOllamaKeyRequest(agentId, usedOllamaKey);
                return reply;
            }
            catch (OperationCanceledException)
            {
                // Rollback to checkpoint
                lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                return null;
            }
            catch
            {
                // Rollback to checkpoint
                lock (_histLock) { while (_history.Count > checkpoint) _history.RemoveAt(_history.Count - 1); }
                return null;
            }
            finally
            {
                resp?.Dispose();
            }
        }

