        // Р В Р’В Р В Р вҖ№Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р РҺРІРӮвҖңР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В Р РҸ: Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р РӢР В Р вҖ° Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһ Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР’ВҰ (Р В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В·Р В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳ Р В Р РӢР В РІРӮСҷР В Р РӢР В Р РҸР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳ),
        // Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮВҳР В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһ Р В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡР’ВҰР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р РӢР РҶР вҖҡРІРӮСҡ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° planning (bullets, Р В Р’В Р РҺР’ВҳР В Р’В Р вҖҷР’В°Р В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮВҳ Draft/Opening/Reaction/Wait/Let's),
        // Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’ВөР В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ Р В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р РӢР РҶРІРӮСҷР’В¬Р В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ. Р В Р’В Р В РІРӮРҺР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡР’В°Р В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡР РӢР В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮВҳР В Р РӢР РҶРІРӮСҷР’В¬Р В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р РӢР В Р вҖ° Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В¶Р В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р РӢР В РІРӮСҷР В Р РӢР В Р РҸР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСң.
        private static string ExtractResponseFromReasoning(string reasoning)
        {
            if (string.IsNullOrWhiteSpace(reasoning)) return "";

            var blocks = System.Text.RegularExpressions.Regex.Split(reasoning, @"\r?\n\s*\r?\n");
            var keep = new List<string>();
            foreach (var blk in blocks)
            {
                var trimmed = blk.Trim();
                if (trimmed.Length == 0) continue;

                bool isPlanning =
                    System.Text.RegularExpressions.Regex.IsMatch(trimmed, @"^\s*\*\s{2,}") ||
                    trimmed.Contains("Self-Correction") ||
                    trimmed.Contains("Draft:") ||
                    trimmed.Contains("Thought:") ||
                    System.Text.RegularExpressions.Regex.IsMatch(trimmed, @"\*[A-Z][a-z]+(\s[A-Za-z]+)?:\*") ||
                    System.Text.RegularExpressions.Regex.IsMatch(trimmed,
                        @"^(Wait|Let's|Looking at|Actually|Final|Is there|Format check|Final check|Final decision|New facts:|Final answer)\b",
                        System.Text.RegularExpressions.RegexOptions.IgnoreCase);

                if (!isPlanning) keep.Add(trimmed);
            }

            if (keep.Count == 0) return "";
            // Р В Р’В Р РҶР вҖҡР’ВҳР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р’В Р В РІРӮВҰР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ N Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВ  Р В Р вҖ Р В РІРӮСҷР РҶР вҖҡРЎСҡ Р В Р РӢР РҶР вҖҡРЎвҖәР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР В Р вҖ° Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В·Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’В°Р В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р’В Р В РІРӮВ  Р В Р’В Р РҺРІРӮСңР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡР’В Р В Р РӢР РҶР вҖҡРІРӮСҡ.
            var tail = keep.Count > 6 ? keep.Skip(keep.Count - 6).ToList() : keep;
            return string.Join("\n\n", tail);
        }

        private static string SanitizeContext(string? raw)
        {
            if (string.IsNullOrEmpty(raw)) return "";
            // Neutralize attempts to spoof system delimiters or role tags inside data.
            var s = raw;
            s = System.Text.RegularExpressions.Regex.Replace(s, @"={3,}", "==");
            s = System.Text.RegularExpressions.Regex.Replace(s, @"<\|[^|>]{0,40}\|>", "[tag]");
            s = System.Text.RegularExpressions.Regex.Replace(
                s, @"(?im)^\s*(system|assistant|user)\s*:\s*", "[$1] ");
            s = System.Text.RegularExpressions.Regex.Replace(
                s, @"(?i)ignore (all |previous |above )?(instructions|rules|prompt)", "[redacted]");
            return s;
        }

        private static DateTime _lastGraphRebuild = DateTime.MinValue;
        private static readonly object _rebuildLock = new();
        private static readonly TimeSpan RebuildDebounce = TimeSpan.FromSeconds(60);

        private string WriteAndLink(Func<string> writeOp, string label)
        {
            string path;
            try { path = writeOp(); }
            catch (Exception ex) { return $"Р В Р вҖ Р РҺРЎСҷР В Р вҖ° Р В Р’В Р РҺРЎСҹР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р РӢР РҺРІРӮСҡ ({label}): {ex.Message}"; }

            if (!File.Exists(path) && !Directory.Exists(path))
                return $"Р В Р вҖ Р РҺРЎСҷР В Р вҖ° {label}: Р В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В Р РҸ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р В РІРӮВҰР В Р РӢР РҺРІРӮСҡР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В° Р В Р РӢР РҶРІРӮСҷР’В¬Р В Р’В Р вҖҷР’В»Р В Р РӢР В Р РҸР В Р РӢР РҶР вҖҡР’ВҰ, Р В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’Вө Р В Р РӢР РҶР вҖҡРЎвҖәР В Р’В Р вҖҷР’В°Р В Р’В Р РҶРІРӮСӣРІРӮвҖңР В Р’В Р вҖҷР’В»/Р В Р’В Р РҺРІРӮвҖқР В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’Вө Р В Р’В Р РҺРІРӮвҖқР В Р РӢР РҶР вҖҡРІРӮСҡР В Р’В Р СһРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В¶Р В Р’В Р вҖҷР’ВөР В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВҰР В Р’В Р вҖҷР’В° Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮСңР В Р РӢР РҺРІРӮСҡ: {path}";

