            string? agentId = "chat")
        {
            var dateStamp = $"\n\n=== Р В Р’В Р РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮв„ўР В Р’В Р РҺРЎвҖәР В Р’В Р РҺРІРӮв„ў/Р В Р’В Р вҖҷР’В§Р В Р’В Р РҺРІРӮв„ўР В Р’В Р В Р вҖ№ ===\nР В Р’В Р В Р вҖ№Р В Р РӢР В Р вҖ°Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮвҖңР В Р’В Р РҺРІРӮСһР В Р’В Р СһРІРӮВҳР В Р’В Р В РІРӮВҰР В Р РӢР РҶР вҖҡРІРӮСҡ: {DateTime.Now:dddd, dd MMMM yyyy}, {DateTime.Now:HH:mm}";
            var continuity = string.IsNullOrWhiteSpace(extraContext)
                ? ""
                : "\n\n=== SHARED CONTINUITY ===\n" + extraContext.Trim();
            var systemContent = TG_SYSTEM_PROMPT + BuildCapabilityPrompt(agentId) + dateStamp + continuity;

            // Р В Р’В Р вҖҷР’ВӨР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р’В Р РҺР’ВҳР В Р РӢР РҺРІРӮСҡР В Р РӢР РҶР вҖҡРЎСҡР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В РІРӮСҷР В Р’В Р РҺРІРӮСһР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮВҳР В Р’В Р РҶРІРӮСӣРІРӮвҖң Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ў Р В Р’В Р вҖҷР’ВұР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В· Р В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР В РЎвҖңР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р РҺРІРӮСһР В Р РӢР В РІРӮСҷР В Р РӢР РҶР вҖҡРІРӮСҡР В Р РӢР РҶР вҖҡРІРӮСң
            var messages = new List<object>
            {
                new { role = "system", content = systemContent },
                new { role = "user", content = userText }
            };

            var target = ResolveAgentTarget(agentId);
            var isClaude = target.Provider.Equals("claude", StringComparison.OrdinalIgnoreCase);
            var isOllamaCloud = target.Provider.Equals("ollama-cloud", StringComparison.OrdinalIgnoreCase);
            var targetUrl = target.Url;
            var targetModel = target.Model;

            object reqBody;
            if (isClaude)
            {
                reqBody = new
                {
                    model = targetModel,
                    max_tokens = MainMaxTokens,
                    temperature = 0.5,
                    system = systemContent,
                    messages = new[] { new { role = "user", content = userText } }
                };
            }
            else
            {
                reqBody = new
                {
                    model = targetModel,
                    max_tokens = MainMaxTokens,
                    temperature = 0.5,
                    messages = messages,
                    stream = false
                };
            }

            try
            {
                var bodyJson = JsonConvert.SerializeObject(reqBody);
                var attempts = isOllamaCloud ? GetOllamaAttemptCount(agentId) : 1;
                HttpResponseMessage? res = null;
                string raw = "";
                string? usedOllamaKey = null;

                for (var attempt = 0; attempt < attempts; attempt++)
                {
                    using var req = new HttpRequestMessage(HttpMethod.Post, targetUrl);

                    if (isClaude)
                        req.Headers.Add("x-api-key", _claudeApiKey);
                    else if (isOllamaCloud)
                    {
                        usedOllamaKey = ResolveOllamaKey(agentId);
                        if (!string.IsNullOrWhiteSpace(usedOllamaKey))
                            req.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", usedOllamaKey);
                    }

                    req.Content = new StringContent(bodyJson, Encoding.UTF8, "application/json");

                    res = await _http.SendAsync(req, ct);
                    raw = await res.Content.ReadAsStringAsync(ct);

                    if (res.IsSuccessStatusCode)
                    {
                        if (isOllamaCloud && !string.IsNullOrWhiteSpace(usedOllamaKey))
                            RecordOllamaKeyRequest(agentId, usedOllamaKey);
                        break;
                    }

                    if (isOllamaCloud && (int)res.StatusCode == 429 && !string.IsNullOrWhiteSpace(usedOllamaKey))
                    {
                        MarkOllamaKeyRateLimited(agentId, usedOllamaKey);
                        res.Dispose();
                        res = null;
                        continue;
                    }

                    break;
                }

                if (res == null || !res.IsSuccessStatusCode)
                {
                    System.Diagnostics.Debug.WriteLine($"[LLM:TG] Error: {raw}");
                    return "Р В РЎвҖ“Р В РІРӮСҷР РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° LLMР В РЎвҖ“Р В РІРӮСҷР РҶР вҖҡРЎСӣ";
                }

                var json = JObject.Parse(raw);

                string text;
                if (isClaude)
                {
                    var content = json["content"] as JArray;
                    text = content?.FirstOrDefault()?["text"]?.ToString() ?? "";
                }
                else
                {
                    var choices = json["choices"] as JArray;
                    text = choices?.FirstOrDefault()?["message"]?["content"]?.ToString() ?? "";
                }

                return text;
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"[LLM:TG] Exception: {ex.Message}");
                return "Р В РЎвҖ“Р В РІРӮСҷР РҶР вҖҡРЎСҡР В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р РҺР’ВҳР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В РЎвҖ“Р В РІРӮСҷР РҶР вҖҡРЎСӣ";
            }
        }
    }
}
